using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;public class EhrServiceTests_DeleteEhrFile_WithFakeIds_ShouldReturnNotFound : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "EhrService"    };    [SkippableFact]    public async Task DeleteEhrFile_WithFakeIds_ShouldReturnNotFound()    {    await AuthenticateAsAdminAsync(EhrClient);    var response = await DeleteWithRetryAsync(EhrClient, ApiEndpoints.Ehr.DeleteFile(Guid.NewGuid(), Guid.NewGuid()));        Assert.True(response.StatusCode == HttpStatusCode.NoContent || response.StatusCode == HttpStatusCode.NotFound);    }}
